## 3. Spring Cache + Redis 적용 방법

### 3-1. 의존성 추가

각 서비스 모듈의 `build.gradle.kts`에 추가합니다.

```kotlin
// user/build.gradle.kts, feed/build.gradle.kts 등
dependencies {
    implementation(project(":domain"))
    implementation(project(":protobuf"))

    // 기존 의존성 유지
    implementation("org.springframework.boot:spring-boot-starter-data-jpa")

    // Redis 캐시 추가
    implementation("org.springframework.boot:spring-boot-starter-data-redis")
    implementation("org.springframework.boot:spring-boot-starter-cache")
}
```

`domain` 모듈은 독립 모듈이므로 Redis 의존성은 각 서비스 모듈에만 추가합니다.

### 3-2. Redis 설정 클래스

```kotlin
// user/src/main/kotlin/com/maum/backend/config/CacheConfig.kt
@Configuration
@EnableCaching
class CacheConfig {

    @Bean
    fun redisConnectionFactory(
        @Value("\${spring.redis.host}") host: String,
        @Value("\${spring.redis.port}") port: Int,
    ): RedisConnectionFactory {
        val config = RedisStandaloneConfiguration(host, port)
        return LettuceConnectionFactory(config)
    }

    @Bean
    fun cacheManager(redisConnectionFactory: RedisConnectionFactory): RedisCacheManager {
        val defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
            .entryTtl(Duration.ofMinutes(10))
            .serializeKeysWith(
                RedisSerializationContext.SerializationPair.fromSerializer(StringRedisSerializer())
            )
            .serializeValuesWith(
                RedisSerializationContext.SerializationPair.fromSerializer(
                    GenericJackson2JsonRedisSerializer()
                )
            )

        // 캐시별 개별 TTL 설정
        val cacheConfigurations = mapOf(
            CacheNames.USER_PROFILE    to defaultConfig.entryTtl(Duration.ofMinutes(30)),
            CacheNames.PRODUCT_LIST    to defaultConfig.entryTtl(Duration.ofHours(6)),
            CacheNames.FOLLOW_COUNT    to defaultConfig.entryTtl(Duration.ofMinutes(5)),
            CacheNames.STATIC_CODE     to defaultConfig.entryTtl(Duration.ofDays(1)),
            CacheNames.FEED_LIST       to defaultConfig.entryTtl(Duration.ofSeconds(30)),
            CacheNames.CHAT_ROOM_META  to defaultConfig.entryTtl(Duration.ofMinutes(10)),
        )

        return RedisCacheManager.builder(redisConnectionFactory)
            .cacheDefaults(defaultConfig)
            .withInitialCacheConfigurations(cacheConfigurations)
            .build()
    }
}
```

```kotlin
// 캐시 이름 상수 관리
object CacheNames {
    const val USER_PROFILE   = "user:profile"
    const val PRODUCT_LIST   = "product:list"
    const val FOLLOW_COUNT   = "follow:count"
    const val STATIC_CODE    = "static:code"
    const val FEED_LIST      = "feed:list"
    const val CHAT_ROOM_META = "chat:room:meta"
}
```

