## 5. 구체적인 Before / After 코드 예시

### 예시 1: 사용자 프로필 캐시

**Before - 매 요청마다 DB 조회**

```kotlin
// user/src/main/kotlin/com/maum/backend/service/UserService.kt
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    // 매 호출마다 DB 2회 조회 발생
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NoSuchElementException("사용자 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
        return UserProfileResponse.from(user, profile)
    }

    fun updateProfile(userId: String, request: UpdateProfileRequest): UserProfileResponse {
        val profile = profileRepository.findByUserId(userId)
        profile.update(request.nickname, request.bio, request.imageUrl)
        profileRepository.save(profile)
        return UserProfileResponse.from(profile)
    }
}
```

**After - Redis 캐시 적용**

```kotlin
@Service
class UserService(
    private val userRepository: UserRepository,
    private val profileRepository: ProfileRepository,
) {
    // 캐시 히트 시 DB 조회 0회, 캐시 미스 시 DB 2회 → Redis 1회
    @Cacheable(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "#userId",
        unless = "#result == null",
    )
    fun getUserProfile(userId: String): UserProfileResponse {
        val user = userRepository.findById(userId)
            .orElseThrow { NoSuchElementException("사용자 없음: $userId") }
        val profile = profileRepository.findByUserId(userId)
        return UserProfileResponse.from(user, profile)
    }

    // 프로필 수정 시 캐시 즉시 무효화
    @CacheEvict(
        cacheNames = [CacheNames.USER_PROFILE],
        key = "#userId",
    )
    fun updateProfile(userId: String, request: UpdateProfileRequest): UserProfileResponse {
        val profile = profileRepository.findByUserId(userId)
        profile.update(request.nickname, request.bio, request.imageUrl)
        profileRepository.save(profile)
        return UserProfileResponse.from(profile)
    }
}
```

**예상 개선 수치:**
- 캐시 히트율 80% 가정 시, DB 쿼리 수 80% 감소
- 프로필 조회 응답 시간: DB 조회 약 15~30ms → Redis 조회 약 1~3ms (10배 개선)

---

### 예시 2: 상품 목록 캐시

**Before**

```kotlin
@Service
class ProductService(private val productRepository: ProductRepository) {
    // 결제 화면 진입마다 전체 상품 목록 DB 조회
    fun getActiveProducts(): List<ProductResponse> {
        return productRepository.findByStatusOrderBySortOrder(status = 1)
            .map { ProductResponse.from(it) }
    }
}
```

**After**

```kotlin
@Service
class ProductService(private val productRepository: ProductRepository) {

    @Cacheable(
        cacheNames = [CacheNames.PRODUCT_LIST],
        key = "'active'",  // 고정 키: 단일 목록
    )
    fun getActiveProducts(): List<ProductResponse> {
        return productRepository.findByStatusOrderBySortOrder(status = 1)
            .map { ProductResponse.from(it) }
    }

    // 관리자가 상품 변경 시 전체 무효화
    @CacheEvict(
        cacheNames = [CacheNames.PRODUCT_LIST],
        allEntries = true,
    )
    fun createProduct(request: CreateProductRequest): ProductResponse {
        val product = productRepository.save(request.toEntity())
        return ProductResponse.from(product)
    }

    @CacheEvict(
        cacheNames = [CacheNames.PRODUCT_LIST],
        allEntries = true,
    )
    fun updateProduct(productId: String, request: UpdateProductRequest): ProductResponse {
        val product = productRepository.findById(productId)
            .orElseThrow { NoSuchElementException("상품 없음") }
        product.update(request)
        productRepository.save(product)
        return ProductResponse.from(product)
    }
}
```

**예상 개선 수치:**
- 상품 목록 변경 빈도: 하루 0~5회 → TTL 6시간 설정으로 DB 쿼리 99%+ 감소
- 결제 화면 응답 시간: 약 20ms → 약 2ms

