### 예시 3: 팔로우 수 캐시 (N+1 위험 구간 대응)

**Before - 피드 목록에서 N+1 발생**

```kotlin
@Service
class FeedService(
    private val feedRepository: FeedRepository,
    private val followRepository: FollowRepository,
) {
    fun getFeedList(page: Int, size: Int): List<FeedResponse> {
        val feeds = feedRepository.findAll(PageRequest.of(page, size))
        // 피드 N개에 대해 팔로워 수 쿼리 N회 발생 (N+1)
        return feeds.map { feed ->
            val followerCount = followRepository.countByTargetUserId(feed.userId)
            FeedResponse.from(feed, followerCount)
        }
    }
}
```

**After - 팔로우 수를 캐시로 N+1 해소**

```kotlin
@Service
class FollowService(private val followRepository: FollowRepository) {

    @Cacheable(
        cacheNames = [CacheNames.FOLLOW_COUNT],
        key = "#userId",
    )
    fun getFollowerCount(userId: String): Long {
        return followRepository.countByTargetUserId(userId)
    }

    @Caching(evict = [
        CacheEvict(cacheNames = [CacheNames.FOLLOW_COUNT], key = "#targetUserId"),
    ])
    fun follow(followerId: String, targetUserId: String) {
        followRepository.save(FollowEntity(followerId = followerId, targetUserId = targetUserId))
    }

    @Caching(evict = [
        CacheEvict(cacheNames = [CacheNames.FOLLOW_COUNT], key = "#targetUserId"),
    ])
    fun unfollow(followerId: String, targetUserId: String) {
        followRepository.deleteByFollowerIdAndTargetUserId(followerId, targetUserId)
    }
}

@Service
class FeedService(
    private val feedRepository: FeedRepository,
    private val followService: FollowService,  // 캐시 적용된 서비스 사용
) {
    fun getFeedList(page: Int, size: Int): List<FeedResponse> {
        val feeds = feedRepository.findAll(PageRequest.of(page, size))
        // 팔로우 수는 Redis 캐시에서 조회 (DB 쿼리 N회 → Redis N회, 이후 캐시 히트 시 0회)
        return feeds.map { feed ->
            val followerCount = followService.getFollowerCount(feed.userId)
            FeedResponse.from(feed, followerCount)
        }
    }
}
```

**예상 개선 수치:**
- N+1 쿼리 N회 → 캐시 히트 시 0회 (DB 쿼리 완전 제거)
- 피드 목록 20개 기준 응답: DB 21회 쿼리(20ms x 21 = 420ms) → 캐시 히트 시 1회 쿼리(20ms) + Redis(1ms x 20 = 20ms) = 약 40ms (10배 개선)

